1430	// ── Tabtarget-refusal cases ─────────────────────────────────
1431	
1432	/// rbw-dU empty-arg refusal — BBAA9 contract. Invoking rbw-dU with no
1433	/// argument must die non-zero and emit the rbw-dl pointer (operator
1434	/// discovery for candidate depot project IDs). BUW dispatch merges
1435	/// stderr→stdout via `2>&1` (bud_dispatch.sh:372), so the captured
1436	/// stdout carries the buc_warn/buc_info/buc_tabtarget/buc_die output
1437	/// from rbgp_depot_unmake's no-arg branch (rbgp_Payor.sh:937-942).
1438	///
1439	/// Pure shell, no GCP traffic — refusal lands before authenticate.
1440	fn rbtdrf_rs_unmake_empty_arg_refusal(dir: &Path) -> rbtdre_Verdict {
1441	    let root = match std::env::current_dir() {
1442	        Ok(r) => r,
1443	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1444	    };
1445	
1446	    let tt = match rbtdri_find_tabtarget_global(&root, RBTDGC_UNMAKE_DEPOT) {
1447	        Ok(p) => p,
1448	        Err(e) => return rbtdre_Verdict::Fail(e),
1449	    };
1450	
1451	    let output = match Command::new(&tt).current_dir(&root).output() {
1452	        Ok(o) => o,
1453	        Err(e) => {
1454	            return rbtdre_Verdict::Fail(format!(
1455	                "failed to run {}: {}",
1456	                tt.display(),
1457	                e
1458	            ));
1459	        }
1460	    };
1461	
1462	    let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
1463	    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
1464	    let code = output.status.code().unwrap_or(-1);
1465	    let _ = std::fs::write(dir.join("empty-arg-stdout.txt"), &stdout);
1466	    let _ = std::fs::write(dir.join("empty-arg-stderr.txt"), &stderr);
1467	
1468	    if code == 0 {
1469	        return rbtdre_Verdict::Fail(format!(
1470	            "{} exited 0 with no argument — BBAA9 empty-arg refusal contract violated",
1471	            RBTDGC_UNMAKE_DEPOT
1472	        ));
1473	    }
1474	
1475	    let combined = format!("{}{}", stdout, stderr);
1476	    if !combined.contains(RBTDGC_LIST_DEPOT) {
1477	        return rbtdre_Verdict::Fail(format!(
1478	            "{} empty-arg refusal did not point at {} for operator discovery\n\
