1488	//
1489	// Drives the Dockerfile FROM-line hygiene contract through the rbw-fhc and
1490	// rbw-fhv tabtargets — exercising the contract surface, not module internals.
1491	// Eight synthetic cases (5 positive, 3 negative) feed inline Dockerfile bodies
1492	// to rbw-fhc; one all-vessels case iterates real conjure vessels through
1493	// rbw-fhv with a Rust-side counter that fails verdict on zero iterations.
1494	
1495	const RBTDRF_DH_BODY_PARAMETERIZED: &str = "FROM ${RBF_IMAGE_1}\n";
1496	const RBTDRF_DH_BODY_SCRATCH: &str = "FROM scratch\n";
