1562	fn rbtdrf_dh_all_vessels_pass(dir: &Path) -> rbtdre_Verdict {
1563	    let root = match std::env::current_dir() {
1564	        Ok(r) => r,
1565	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1566	    };
1567	
1568	    // Resolve RBRR_VESSEL_DIR via one-shot bash (kindle ceremony unavoidable
1569	    // for derived-path resolution).
1570	    let buv = root.join("Tools/buk/buv_validation.sh");
1571	    let rbk = root.join("Tools/rbk");
1572	    let buv_p = rbtdrx_native_to_posix(&buv);
1573	    let rbk_p = rbtdrx_native_to_posix(&rbk);
1574	    let resolve_script = format!(
1575	        "set -euo pipefail\n\
1576	         source '{}'\n\
1577	         source '{}/rbcc_Constants.sh'\n\
1578	         source '{}/rbgc_Constants.sh'\n\
1579	         source '{}/rbrr_regime.sh'\n\
1580	         source '{}/rbrd_regime.sh'\n\
1581	         source '{}/rbdc_DerivedConstants.sh'\n\
1582	         zbuv_kindle\nzrbcc_kindle\n\
1583	         source \"${{PWD}}/{moorings}/rbrr.env\"\n\
1584	         source \"${{PWD}}/{moorings}/rbrd.env\"\n\
1585	         zrbrr_kindle\nzrbrd_kindle\nzrbrr_enforce\nzrbrd_enforce\nzrbdc_kindle\n\
1586	         printf '%s' \"${{RBRR_VESSEL_DIR}}\"",
1587	        buv_p,
1588	        rbk_p, rbk_p, rbk_p, rbk_p, rbk_p,
1589	        moorings = crate::rbtdgc_consts::RBTDGC_MOORINGS_DIR,
1590	    );
1591	    let vessel_dir = match rbtdrf_run_bash(&root, &resolve_script, dir, "resolve-vessel-dir") {
1592	        Ok((0, stdout, _)) => stdout,
1593	        Ok((code, _, stderr)) => {
1594	            return rbtdre_Verdict::Fail(format!(
1595	                "resolve RBRR_VESSEL_DIR failed (exit {}): {}",
1596	                code, stderr
1597	            ));
1598	        }
1599	        Err(e) => return rbtdre_Verdict::Fail(e),
1600	    };
1601	    let vessel_dir = vessel_dir.trim();
1602	    if vessel_dir.is_empty() {
1603	        return rbtdre_Verdict::Fail("RBRR_VESSEL_DIR resolved to empty string".to_string());
1604	    }
1605	
1606	    let entries = match std::fs::read_dir(vessel_dir) {
1607	        Ok(e) => e,
1608	        Err(e) => {
1609	            return rbtdre_Verdict::Fail(format!(
1610	                "read_dir({}) failed: {}",
1611	                vessel_dir, e
1612	            ));
1613	        }
1614	    };
1615	
1616	    // rbw-fhv silently succeeds on non-conjure vessels (hygiene contract is
1617	    // vacuously satisfied where there's no local Dockerfile), so theurge
1618	    // iterates without pre-filtering — surface integrity stays intact and
1619	    // no rbrv.env internals are touched here.
1620	    let mut count: usize = 0;
1621	    for entry in entries {
1622	        let entry = match entry {
1623	            Ok(e) => e,
1624	            Err(e) => return rbtdre_Verdict::Fail(format!("dir entry error: {}", e)),
1625	        };
1626	        let path = entry.path();
1627	        if !path.is_dir() {
1628	            continue;
1629	        }
1630	        if !path.join("rbrv.env").is_file() {
1631	            continue;
1632	        }
1633	        let sigil = match path.file_name().and_then(|s| s.to_str()) {
1634	            Some(s) => s.to_string(),
1635	            None => continue,
1636	        };
1637	
1638	        if let Err(e) = rbtdrf_run_tt(
1639	            &root,
1640	            RBTDGC_HYGIENE_CHECK_VESSEL,
1641	            &[&sigil],
1642	            dir,
1643	            &format!("vessel-{}", sigil),
1644	        ) {
1645	            return rbtdre_Verdict::Fail(e);
1646	        }
1647	        count += 1;
1648	    }
1649	
1650	    if count == 0 {
1651	        return rbtdre_Verdict::Fail(format!(
1652	            "zero vessels iterated under {} — busted RBRR_VESSEL_DIR resolution",
1653	            vessel_dir
1654	        ));
1655	    }
1656	
1657	    rbtdre_Verdict::Pass
1658	}
