/// `tools_subdir` is the repo-relative directory holding the module
/// ("Tools/rbk" or "Tools/buk"). `prereqs` are sibling modules sourced and
/// kindled after buv but before the regime module — for regimes whose enforce
/// reaches a neighbor (rbrp → rbgc); empty for the common case, mirroring how
/// rbtdrf_rs_rbrr_nonempty_prefix stages rbgc in-harness.
fn rbtdrf_run_probate_in(
    dir: &Path,
    tools_subdir: &str,
    module: &str,
    probate_fn: &str,
    prereqs: &[(&str, &str)],
    baseline: &str,
    override_: &str,
    expect_ok: bool,
    label: &str,
) -> rbtdre_Verdict {
    let root = match std::env::current_dir() {
        Ok(r) => r,
        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
    };
    let buv = root.join("Tools/buk/buv_validation.sh");
    let module_path = root.join(tools_subdir).join(module);

    let env_file = dir.join(format!("{}.env", label));
    let body = format!("{}\n{}\n", baseline, override_);
    if let Err(e) = std::fs::write(&env_file, &body) {
        return rbtdre_Verdict::Fail(format!("{}: write env failed: {}", label, e));
    }

    let mut prelude = String::new();
    for (relpath, kindle_fn) in prereqs {
        prelude.push_str(&format!(
            "source '{}'\n{}\n",
            rbtdrx_native_to_posix(&root.join(relpath)),
            kindle_fn,
        ));
    }

    let script = format!(
        "set -euo pipefail\n\
         source '{}'\n\
         source '{}'\n\
         zbuv_kindle\n\
         {}\
         {} '{}'",
        rbtdrx_native_to_posix(&buv),
        rbtdrx_native_to_posix(&module_path),
        prelude,
        probate_fn,
        rbtdrx_native_to_posix(&env_file),
    );

